    /* ─── OWNERSHIP CHART (Chart.js) ─────────── */
    function OwnershipChart({ theme }) {
        const canvasRef = useRef(null);
        const chartRef = useRef(null);

        useEffect(() => {
            if (!canvasRef.current) return;
            if (chartRef.current) { chartRef.current.destroy(); chartRef.current = null; }

            const isDark = theme === "dark";
            const mutedColor = isDark ? "#8b90a8" : "#6b7394";

            chartRef.current = new window.Chart(canvasRef.current, {
                type: "doughnut",
                data: {
                    labels: ["James Brown", "Ozan Isinak", "Chris Kramer", "Randy Smith"],
                    datasets: [{
                        data: [73.20, 16.27, 7.25, 3.29],
                        backgroundColor: ["#1a5276", "#2e86c1", "#148f77", "#7d3c98"],
                        borderWidth: 0,
                        hoverOffset: 6,
                    }],
                },
                options: {
                    responsive: false,
                    cutout: "62%",
                    plugins: {
                        legend: {
                            position: "bottom",
                            labels: {
                                color: mutedColor,
                                font: { family: "'General Sans', 'DM Sans', sans-serif", size: 12, weight: 500 },
                                padding: 16,
                                usePointStyle: true,
                                pointStyleWidth: 10,
                            },
                        },
                        tooltip: {
                            backgroundColor: isDark ? "#1e2130" : "#1a1f36",
                            titleFont: { family: "'General Sans', 'DM Sans', sans-serif", size: 13, weight: 600 },
                            bodyFont: { family: "'General Sans', 'DM Sans', sans-serif", size: 12 },
                            cornerRadius: 8,
                            padding: 12,
                            callbacks: { label: (ctx) => ctx.label + ": " + ctx.parsed.toFixed(2) + "%" },
                        },
                    },
                },
            });

            return () => { if (chartRef.current) { chartRef.current.destroy(); chartRef.current = null; } };
        }, [theme]);

        return (
            <div className="ip-chart-container">
                <canvas ref={canvasRef} width="340" height="340" />
            </div>
        );
    }
